onClick:
{{
!inpIngredient.text?.trim()
  ? showAlert("Ingredient name is required.", "warning")
  : !selCategory.selectedOptionValue
    ? showAlert("Category is required.", "warning")
    : !inpQuantity.text
      ? showAlert("Purchase quantity is required.", "warning")
      : !selPurchaseUnit.selectedOptionValue
        ? showAlert("Purchase unit is required.", "warning")
        : !inpPurchaseCost.text
          ? showAlert("Purchase price is required.", "warning")
          : checkIngredientNameExists.run(() => {
              if (checkIngredientNameExists.data?.[0]?.match_count > 0) {
                showAlert("Ingredient name already exists. Choose another name.", "warning");
              } else {
                addIngredient.run(() => {
                  const newId = addIngredient.data?.[0]?.id;
                  if (!newId) {
                    showAlert("Ingredient was not created. Tags not saved.", "error");
                    return;
                  }

                  addIngredientAllergens.run(() => {
                    addIngredientDietTags.run(() => {
                      getIngredients.run();
                      closeModal("mdlAddIngredient");
                      showAlert("Ingredient added", "success");
                    }, () => showAlert("Could not save diet tags.", "error"));
                  }, () => showAlert("Could not save allergens.", "error"));
                }, () => showAlert("Could not add ingredient.", "error"));
              }
            })
}}
